nodes.notes:
Google Contacts — manage contacts including lookup, create, update, and delete.

Actions:
  search — find a contact by name. Use when you need someone's email, phone, or contact_id.
  list — list all contacts.
  create — add a new contact. Use for "add contact", "save this number".
  update — modify an existing contact. Requires contact_id from a prior search. Only include fields you want to change.
  delete — remove a contact. Requires contact_id from a prior search.

Rules:
- contact_id comes from search or list results. Do not fabricate contact IDs.
- For update, only send fields that should change. Omitted fields remain unchanged.
- first_name is required for create.

---schema
{
  "action": {
    "type": "string",
    "description": "One of: search, list, create, update, delete",
    "required": true
  },
  "query": {
    "type": "string",
    "description": "Name to search for. For: search"
  },
  "limit": {
    "type": "integer",
    "description": "Max contacts to return. Default 10. For: list"
  },
  "first_name": {
    "type": "string",
    "description": "First/given name. For: create, update"
  },
  "last_name": {
    "type": "string",
    "description": "Last/family name. For: create, update"
  },
  "email": {
    "type": "string",
    "description": "Email address. For: create, update"
  },
  "phone": {
    "type": "string",
    "description": "Phone number. For: create, update"
  },
  "company": {
    "type": "string",
    "description": "Company/organization name. For: create, update"
  },
  "contact_id": {
    "type": "string",
    "description": "Contact resource name from search/list results (e.g. people/c1234). For: update, delete"
  }
}

parameters.jsCode:
const body = $input.item.json.body || {};

let data;
if (typeof body === 'string') {
  data = JSON.parse(body);
} else if (typeof body === 'object') {
  data = body;
} else {
  data = $input.item.json;
}

const action = (data.action || 'search').toLowerCase();
const query = data.query || data.name || '';
const limit = parseInt(data.limit) || 10;
const first_name = data.first_name || '';
const last_name = data.last_name || '';
const email = data.email || '';
const phone = data.phone || '';
const company = data.company || '';
const contact_id = (data.contact_id || '').replace('people/', '');

return [{ json: { action, query, queryLower: query.toLowerCase(), limit, first_name, last_name, email, phone, company, contact_id } }];

const contacts = items;
const query = $('Parse Parameters').first().json.queryLower;

if (!query) {
  return { message: 'Please provide a name to search for.', found: false, contacts: [] };
}

const matches = contacts.filter(item => {
  const c = item.json;
  const displayName = (c.names?.displayName || '').toLowerCase();
  let nicknames = [];
  if (c.nicknames) {
    for (const vals of Object.values(c.nicknames)) {
      if (Array.isArray(vals)) {
        vals.forEach(v => { if (typeof v === 'string') nicknames.push(v.toLowerCase()); });
      } else if (typeof vals === 'string') {
        nicknames.push(vals.toLowerCase());
      }
    }
  }
  const allNames = [displayName, ...nicknames];
  return allNames.some(name => name.includes(query));
});

if (matches.length === 0) {
  return { message: `No contacts found matching "${$('Parse Parameters').first().json.query}".`, found: false, contacts: [] };
}

const formatted = matches.map(item => {
  const c = item.json;
  const name = c.names?.displayName || 'Unknown';
  const contact_id = c.resourceName || null;

  const emailObj = c.emailAddresses || {};
  const emails = [];
  for (const [type, addrs] of Object.entries(emailObj)) {
    if (Array.isArray(addrs)) {
      addrs.forEach(email => emails.push({ email, type }));
    }
  }

  const phoneObj = c.phoneNumbers || {};
  const phones = [];
  for (const [type, nums] of Object.entries(phoneObj)) {
    if (Array.isArray(nums)) {
      nums.forEach(phone => phones.push({ phone, type }));
    }
  }

  const primaryEmail = emails[0]?.email || null;
  const primaryPhone = phones[0]?.phone || null;

  return { contact_id, name, email: primaryEmail, phone: primaryPhone, emails, phones };
});

let message = '';
if (formatted.length === 1) {
  const c = formatted[0];
  const parts = [c.name];
  if (c.email) parts.push(`email ${c.email}`);
  if (c.phone) parts.push(`phone ${c.phone}`);
  message = parts.join(', ') + '.';
} else {
  message = `Found ${formatted.length} contacts matching "${$('Parse Parameters').first().json.query}": `;
  const names = formatted.slice(0, 3).map(c => c.name);
  message += names.join(', ');
  if (formatted.length > 3) message += `, and ${formatted.length - 3} more`;
  message += '.';
}

return { message, found: true, count: formatted.length, contacts: formatted };

const contacts = items;
const limit = $('Parse Parameters').first().json.limit;

if (contacts.length === 0) {
  return { message: 'No contacts found.', count: 0, contacts: [] };
}

const formatted = contacts.map(item => {
  const c = item.json;
  const name = c.names?.displayName || 'Unknown';
  const contact_id = c.resourceName || null;

  const emailObj = c.emailAddresses || {};
  const emails = [];
  for (const [type, addrs] of Object.entries(emailObj)) {
    if (Array.isArray(addrs)) {
      addrs.forEach(email => emails.push({ email, type }));
    }
  }

  const phoneObj = c.phoneNumbers || {};
  const phones = [];
  for (const [type, nums] of Object.entries(phoneObj)) {
    if (Array.isArray(nums)) {
      nums.forEach(phone => phones.push({ phone, type }));
    }
  }

  const primaryEmail = emails[0]?.email || null;
  const primaryPhone = phones[0]?.phone || null;

  return { contact_id, name, email: primaryEmail, phone: primaryPhone, emails, phones };
});

let message = '';
if (formatted.length === 1) {
  message = `You have 1 contact: ${formatted[0].name}.`;
} else {
  message = `Listing ${formatted.length} contacts: `;
  const names = formatted.slice(0, 5).map(c => c.name);
  message += names.join(', ');
  if (formatted.length > 5) message += `, and ${formatted.length - 5} more`;
  message += '.';
}

return { message, count: formatted.length, contacts: formatted };

const c = $input.item.json;
const params = $('Parse Parameters').first().json;
const name = [params.first_name, params.last_name].filter(Boolean).join(' ') || 'contact';

const parts = [`Done. Created ${name}`];
if (params.email) parts.push(`email ${params.email}`);
if (params.phone) parts.push(`phone ${params.phone}`);
if (params.company) parts.push(`at ${params.company}`);

return [{ json: { message: parts.join(', ') + '.', action: 'create', contact_id: c.resourceName || null } }];

const c = $input.item.json;
const params = $('Parse Parameters').first().json;
const name = c.names?.displayName || [params.first_name, params.last_name].filter(Boolean).join(' ') || 'contact';

const changes = [];
if (params.first_name || params.last_name) changes.push('name');
if (params.email) changes.push('email');
if (params.phone) changes.push('phone');
if (params.company) changes.push('company');
const what = changes.length > 0 ? changes.join(', ') : 'details';

return [{ json: { message: `Done. Updated ${what} for ${name}.`, action: 'update', contact_id: c.resourceName || params.contact_id } }];

const errorData = $input.item.json;
let errorMsg = errorData.message || errorData.error || 'Unknown error';
if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}
errorMsg = String(errorMsg);

if (errorMsg.includes('authorization') || errorMsg.includes('token') || errorMsg.includes('invalid_grant')) {
  errorMsg = 'Google Contacts authentication failed. Please re-authorize in n8n.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Google Contacts. Check your internet connection.';
} else if (errorMsg.includes('Credential')) {
  errorMsg = 'Google Contacts credentials not found in n8n.';
} else if (errorMsg.includes('not found') || errorMsg.includes('404')) {
  errorMsg = 'Contact not found. It may have been deleted.';
}

return [{ json: { message: 'Error: ' + errorMsg, error: true } }];
